"use client";

import { useEffect, useRef, useState } from "react";

export function QuoteForm() {
  const startedAt = useRef(0);
  const [message, setMessage] = useState("");
  const [busy, setBusy] = useState(false);

  useEffect(() => { startedAt.current = Date.now(); }, []);

  async function submit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    setBusy(true); setMessage("Talebiniz gönderiliyor…");
    const form = event.currentTarget;
    const data = Object.fromEntries(new FormData(form).entries());
    try {
      const response = await fetch("/api/quote", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ ...data, startedAt: startedAt.current }) });
      const result = await response.json() as { ok?: boolean; error?: string };
      if (!response.ok || !result.ok) throw new Error(result.error || "Talep gönderilemedi.");
      form.reset(); startedAt.current = Date.now();
      setMessage("Talebiniz alındı. Ekibimiz en kısa sürede sizinle iletişime geçecek.");
    } catch (error) { setMessage(error instanceof Error ? error.message : "Talep gönderilemedi."); }
    finally { setBusy(false); }
  }

  return <form className="quote-form" onSubmit={submit}>
    <div className="quote-form-heading"><p className="eyebrow"><span>Teklif</span>Projenizi anlatın</p><h2>Size özel çalışma planı hazırlayalım.</h2></div>
    <div className="quote-fields">
      <label>Ad soyad *<input name="name" required minLength={2} autoComplete="name" /></label>
      <label>Firma adı<input name="company" autoComplete="organization" /></label>
      <label>Telefon<input name="phone" inputMode="tel" autoComplete="tel" /></label>
      <label>E-posta<input name="email" type="email" autoComplete="email" /></label>
      <label>Proje türü<select name="projectType" defaultValue=""><option value="">Seçiniz</option><option>Hafriyat ve kazı</option><option>Altyapı</option><option>İnşaat ve taahhüt</option><option>Makine kiralama</option><option>Diğer</option></select></label>
      <label>Proje konumu<input name="location" /></label>
      <label className="full">Talep detayları *<textarea name="message" required minLength={10} rows={6} /></label>
      <label className="spam-field" aria-hidden="true">Web sitesi<input name="website" tabIndex={-1} autoComplete="off" /></label>
    </div>
    <div className="quote-submit"><button className="button" disabled={busy} type="submit">{busy ? "Gönderiliyor…" : "Teklif talebi gönder"} <span>↗</span></button><p role="status">{message}</p></div>
  </form>;
}
